// Parse incoming signal data from daily scan or manual trigger
const body = $input.first().json.body || $input.first().json;

let signals;
if (typeof body.signals === 'string') {
  signals = JSON.parse(body.signals);
} else if (Array.isArray(body.signals)) {
  signals = body.signals;
} else if (Array.isArray(body)) {
  signals = body;
} else {
  signals = [];
}

// Normalize signal shape
const normalized = signals.map(s => ({
  id: s.id || s.signal_id || crypto.randomUUID(),
  company_name: s.company_name || s.org || s.organization || 'Unknown',
  company_domain: s.company_domain || s.domain || '',
  signal_type: s.signal_type || s.type || 'UNKNOWN',
  icp_score: s.icp_score || s.tier || 'C',
  signal_strength: s.signal_strength || s.strength || 1,
  github_url: s.github_url || s.url || '',
  description: s.description || s.summary || '',
  raw: s
}));

return normalized.map(s => ({ json: s }));

// Merge Clay enrichment data back into the signal
const signal = $('Parse Signal Data').first().json;
const clayResponse = $input.first().json;

const clayData = clayResponse.statusCode === 200 ? (clayResponse.body || {}) : {};

return [{
  json: {
    ...signal,
    clay_enriched: !!clayData.company_name,
    employee_count: clayData.employee_count || signal.employee_count || null,
    industry: clayData.industry || signal.industry || null,
    linkedin_url: clayData.linkedin_url || signal.linkedin_url || null,
    tech_stack: clayData.tech_stack || [],
    funding_stage: clayData.funding_stage || signal.funding_stage || null
  }
}];

// Waterfall: merge contacts from Apollo, Hunter, Prospeo — deduplicate by email
const signal = $('Merge Clay Data').first().json;
const apolloResp = $('Apollo Contact Lookup').first().json;
const hunterResp = $('Hunter Email Lookup').first().json;
const prospeoResp = $('Prospeo LinkedIn Emails').first().json;

const contacts = [];
const seenEmails = new Set();

// Apollo people
const apolloPeople = apolloResp?.organization?.people || [];
for (const p of apolloPeople.slice(0, 3)) {
  const email = p.email;
  if (email && !seenEmails.has(email)) {
    seenEmails.add(email);
    contacts.push({
      source: 'apollo',
      first_name: p.first_name || '',
      last_name: p.last_name || '',
      email,
      title: p.title || '',
      linkedin_url: p.linkedin_url || ''
    });
  }
}

// Hunter emails
const hunterEmails = hunterResp?.data?.emails || [];
for (const e of hunterEmails.slice(0, 3)) {
  if (e.value && !seenEmails.has(e.value)) {
    seenEmails.add(e.value);
    contacts.push({
      source: 'hunter',
      first_name: e.first_name || '',
      last_name: e.last_name || '',
      email: e.value,
      title: e.position || '',
      linkedin_url: e.linkedin || ''
    });
  }
}

// Prospeo
const prospeoEmail = prospeoResp?.email;
if (prospeoEmail && !seenEmails.has(prospeoEmail)) {
  seenEmails.add(prospeoEmail);
  contacts.push({
    source: 'prospeo',
    first_name: prospeoResp.first_name || '',
    last_name: prospeoResp.last_name || '',
    email: prospeoEmail,
    title: prospeoResp.job_title || '',
    linkedin_url: prospeoResp.linkedin_url || ''
  });
}

return [{
  json: {
    ...signal,
    contacts,
    contact_count: contacts.length,
    enrichment_sources: ['apollo', 'hunter', 'prospeo'].filter(
      s => (s === 'apollo' && apolloPeople.length > 0) ||
           (s === 'hunter' && hunterEmails.length > 0) ||
           (s === 'prospeo' && !!prospeoEmail)
    )
  }
}];

// ICP scoring based on signal strength, company attributes, and contact quality
const signal = $('Merge Waterfall Contacts').first().json;
const zbResponse = $input.first().json;

// Filter to valid emails only
const validStatuses = ['valid', 'catch-all'];
const zbResults = zbResponse?.email_batch || [];
const validEmails = new Set(
  zbResults.filter(r => validStatuses.includes(r.status)).map(r => r.address)
);

const verifiedContacts = signal.contacts.map(c => ({
  ...c,
  email_valid: validEmails.has(c.email),
  email_status: zbResults.find(r => r.address === c.email)?.status || 'unknown'
})).filter(c => c.email_valid);

// Score calculation
let score = 0;

// Signal type weights
const typeWeights = {
  GITHUB_RL_REPO: 20,
  ARXIV_PAPER: 15,
  JOB_POSTING: 25,
  HUGGINGFACE_MODEL: 18,
  FUNDING_EVENT: 30
};
score += typeWeights[signal.signal_type] || 10;

// Signal strength multiplier
score *= (signal.signal_strength || 1);

// Company size bonus
if (signal.employee_count > 500) score += 20;
else if (signal.employee_count > 100) score += 15;
else if (signal.employee_count > 20) score += 10;

// Contact quality bonus
if (verifiedContacts.length >= 2) score += 15;
else if (verifiedContacts.length === 1) score += 8;

// Determine ICP score tier
let icp_score;
if (score >= 80) icp_score = 'A';
else if (score >= 55) icp_score = 'B';
else if (score >= 30) icp_score = 'C';
else icp_score = 'D';

return [{
  json: {
    ...signal,
    contacts: verifiedContacts,
    verified_contact_count: verifiedContacts.length,
    icp_score,
    icp_score_raw: score,
    scored_at: new Date().toISOString()
  }
}];

// Add B/C-tier signals to review queue (write to a Google Sheet or just log)
const signal = $('ICP Scoring').first().json;
const dealId = $('HubSpot Upsert Deal').first().json?.id;

return [{
  json: {
    queued_at: new Date().toISOString(),
    company_name: signal.company_name,
    company_domain: signal.company_domain,
    icp_score: signal.icp_score,
    signal_type: signal.signal_type,
    deal_id: dealId,
    contact_count: signal.verified_contact_count,
    action: 'review_queue',
    reason: 'Score below A-tier threshold — manual review required'
  }
}];
